SELECT DISTINCT s.`Song Name`
FROM `singer` AS s;
WHERE s.Age > (SELECT AVG(s2.Age) FROM singer AS s2);

SELECT COUNT(*) AS NumberOfConcerts
FROM concert
WHERE STRFTIME('%Y', year) = '2014' OR STRFTIME('%Y', year) = '2015';

SELECT Singer.Name, Singer.Country
FROM Singer
WHERE Song_Name LIKE '%Hey%';

SELECT DISTINCT s.Name, s.Country
FROM singer AS s
INNER JOIN singer_in_concert AS sc ON s.Singer_ID = sc.Singer_ID
WHERE EXISTS (
    SELECT 1 FROM song INNER JOIN Song_Title ON song.song_name = song_title.title_name WHERE LOWER(Song_Title.contains) LIKE '%hey%'
);

SELECT pets.[weight]
FROM [Pets] AS pets
WHERE pets.pet_age = (SELECT min(pets.pet_age) FROM [Pets] AS subquery WHERE pettype = 'dog');

SELECT COUNT(*) AS NumberOfDogPetsOwnedByFemaleStudents
FROM Has_Pet JOIN Student ON Has_Pet.StuID = Student.StuID
WHERE Student.Sex = 'F' AND EXISTS (SELECT 1 FROM Pets WHERE PetType = 'dog');

SELECT p.`Pet Type`, AVG(p.`pet age`) AS `Average Age`, MAX(p.`pet age`) AS `Maximum Age` 
FROM Pets p 
GROUP BY p.`Pet Type`;

SELECT CountryName, ROW_NUMBER() OVER(ORDER BY CountryId DESC) AS rn
    FROM countries
)
SELECT CountryName FROM RankedCountries WHERE rn = 1;

SELECT cm.id, cm.name
FROM car_makers AS cm
WHERE (SELECT COUNT(*) FROM car_names AS cn WHERE cn.make = cm.maker) > 3;

SELECT CAST(MAX(Horsepower) AS REAL) AS horsepower_value
    FROM cars_data
)
SELECT Horsepower FROM cars_data WHERE Accelerate = (SELECT MAX(Accelerate) FROM cars_data);

SELECT Model FROM cars_data AS cd
INNER JOIN car_names AS cn ON cd.MakeId = cn.MakeId
WHERE cd.Weight < 3500 AND cn.Make <> 'Ford Motor Company';

SELECT COUNT(*) AS NumberOfDeparturesFromAPG
FROM flights
WHERE SourceAirport = 'APG';

SELECT COUNT(*) AS NumberOfDeparturesFromAberdeen
FROM flights
WHERE SourceAirport = 'Aberdeen';

SELECT COUNT(*) AS NumberOfFlightsArrivingInABerdeen
FROM flights
WHERE DestAirport LIKE '%Aberdeen%';

SELECT COUNT(*) FROM (
    SELECT f.flightID
    FROM flights AS f
    JOIN airports AS a1 ON f.departureCity = a1.city AND f.destinationCity = 'Ashley'
    WHERE a1.city = 'Aberdeen'
) AS subquery;

SELECT COUNT(*) AS NumberOfFlights
FROM Flights
WHERE Airline IN (SELECT uid FROM Airlines WHERE Abbreviation = 'JetBlue');

SELECT COUNT(*) AS UnitedFlightsFromAHDS
FROM flights
WHERE Airline = (SELECT uid FROM airlines WHERE Airline = 'United Airlines');
